var countDigitOne = function(n) {
    let count = 0;
    let place = 1;
    while (place <= n) {
        const high = Math.floor(n / (place * 10));
        const cur = Math.floor(n / place) % 10;
        const low = n % place;
        if (cur === 0) count += high * place;
        else if (cur === 1) count += high * place + low + 1;
        else count += (high + 1) * place;
        place *= 10;
    }
    return count;
};
